const output = $input.first().json.output || '';
const chatId = $('Telegram Trigger1').first().json.message.chat.id;
const clean = output.replace(/<br\s*\/?>/gi, '\n').replace(/\r/g, '');
const MAX = 4096;

function closeOpenTags(text) {
  const openTags = [];
  const regex = /<\/?([biu])>/gi;
  let match;
  while ((match = regex.exec(text)) !== null) {
    const full = match[0];
    const tag = match[1].toLowerCase();
    if (full[1] === '/') {
      const index = openTags.lastIndexOf(tag);
      if (index !== -1) openTags.splice(index, 1);
    } else {
      openTags.push(tag);
    }
  }
  return {
    prefix: openTags.map((tag) => `<${tag}>`).join(''),
    suffix: [...openTags].reverse().map((tag) => `</${tag}>`).join(''),
  };
}

function splitText(text) {
  const chunks = [];
  let remaining = text.trim();
  while (remaining.length > MAX) {
    let cut = remaining.lastIndexOf('\n\n', MAX);
    if (cut < MAX * 0.5) cut = remaining.lastIndexOf('\n', MAX);
    if (cut < MAX * 0.5) cut = remaining.lastIndexOf(' ', MAX);
    if (cut < MAX * 0.5) cut = MAX;

    let piece = remaining.slice(0, cut).trim();
    const tags = closeOpenTags(piece);
    piece += tags.suffix;
    chunks.push(piece);
    remaining = (tags.prefix + remaining.slice(cut)).trim();
  }
  if (remaining) chunks.push(remaining);
  return chunks;
}

return splitText(clean).map((text) => ({ json: { text, chatId } }));
